package main

// Compliant: Broken down into focused, manageable functions

// Main orchestration function (10-15 lines)
func processUserRegistration(userData map[string]interface{}) error {
    // Validate input data
    user, err := validateUserInput(userData)
    if err != nil {
        return err
    }

    // Create user account
    userID, err := createUserAccount(user)
    if err != nil {
        return err
    }

    // Handle post-registration tasks
    return handlePostRegistration(user, userID)
}

// Input validation function (15-20 lines)
func validateUserInput(userData map[string]interface{}) (*User, error) {
    user := &User{}

    if userData["name"] == nil || userData["name"].(string) == "" {
        return nil, errors.New("name is required")
    }
    user.Name = userData["name"].(string)

    if userData["email"] == nil {
        return nil, errors.New("email is required")
    }
    user.Email = userData["email"].(string)
    if err := validateEmail(user.Email); err != nil {
        return nil, err
    }

    if userData["password"] == nil {
        return nil, errors.New("password is required")
    }
    if err := validatePassword(userData["password"].(string)); err != nil {
        return nil, err
    }
    user.Password = userData["password"].(string)

    return user, nil
}

