// Database operations function (20-25 lines)
func createUserAccount(user *User) (int64, error) {
    db, err := getDBConnection()
    if err != nil {
        return 0, err
    }
    defer db.Close()

    tx, err := db.Begin()
    if err != nil {
        return 0, err
    }
    defer tx.Rollback()

    // Check for existing user
    if exists, err := userExists(tx, user.Email); err != nil {
        return 0, err
    } else if exists {
        return 0, errors.New("user already exists")
    }

    // Create user record
    userID, err := insertUser(tx, user)
    if err != nil {
        return 0, err
    }

    // Create profile
    if err := createUserProfile(tx, userID); err != nil {
        return 0, err
    }

    return userID, tx.Commit()
}

// Check if user exists (8-10 lines)
func userExists(tx *sql.Tx, email string) (bool, error) {
    var count int
    query := "SELECT COUNT(*) FROM users WHERE email = ?"
    err := tx.QueryRow(query, email).Scan(&count)
    return count > 0, err
}

// Insert user record (10-12 lines)
func insertUser(tx *sql.Tx, user *User) (int64, error) {
    hashedPassword, err := hashPassword(user.Password)
    if err != nil {
        return 0, err
    }

    query := "INSERT INTO users (name, email, password, created_at) VALUES (?, ?, ?, ?)"
    result, err := tx.Exec(query, user.Name, user.Email, hashedPassword, time.Now())
    if err != nil {
        return 0, err
    }

    return result.LastInsertId()
}

// Password hashing function (5-8 lines)
func hashPassword(password string) ([]byte, error) {
    return bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
}

// Post-registration tasks (10-12 lines)
func handlePostRegistration(user *User, userID int64) error {
    // Send welcome email (non-blocking)
    go func() {
        if err := sendWelcomeEmail(user.Email, user.Name); err != nil {
            log.Printf("Failed to send welcome email: %v", err)
        }
    }()

    // Log audit event
    logAuditEvent(userID, "USER_REGISTERED")

    // Send admin notification
    notifyAdmin(user)

    return nil
}
